local Rewards = MemoryPool.newTable()

local function loadConfig()
    local rewards = FileUtil.getConfigFromCsv("setting/RewardSetting.csv", 3)
    for _, reward in pairs(rewards) do
        Rewards[reward.Id] = {
            Id = tonumber(reward.Id),
            Title = reward.Title,
            Name = reward.Name,
            Image = reward.Image,
            Desc = reward.Desc,
            Type = tonumber(reward.Type),
            Count = tonumber(reward.Count),
            CountText = reward.CountText,
            RewardId = tonumber(reward.RewardId),
            RewardType = reward.RewardType
        }
    end
end

loadConfig()

RewardConfig = {}

function RewardConfig.findRewardById(rewardId)
    return Rewards[tostring(rewardId)]
end

function RewardConfig.findRewardByIds(rewardIds)
    local rewards = {}
    local ids = StringUtil.split(rewardIds, "#")
    for _, id in pairs(ids) do
        table.insert(rewards, RewardConfig.findRewardById(id))
    end
    return rewards
end